Kaj izpiše program? 
public class IzpisUganke { 
  public static void main(String[] args) { 
     String s=new String("uganka"); 
     int i=0; int n=0; 
     while (i<s.length()){ 
       switch (s.charAt(i)){ 
           case 'a': 
           case 'e': 
           case 'i': 
           case 'o': 
           case 'u': n++; 
       } 
       i++; 
     } 
     System.out.println(n); 
  } 
}

