Kateri stavek SQL ustvari tabelo Tab(A:N,B:N,C:N)? 
A 
create table Tab(a int not null primary key, b int not null primary 
key, c int no null); 
B 
create table Tab(a int not null, b int not null, c int not null, 
primary key(a), primary key(b)); 
C 
create table Tab(a int not null, b int not null, c int not null, 
primary key(b,c)); 
D 
create table Tab(a int not null, b int not null, c int not null, 
